import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface WeeklyMinutes {
  day: string;
  minutes: number;
}

interface MeditationData {
  currentStreak: number;
  totalSessions: number;
  weeklyMinutes: WeeklyMinutes[];
}

interface MetaData {
  theme: string;
  dataMode: string;
  layout: string;
  primaryColor: string;
  accentColor: string;
  chartTypes: string[];
}

export default function Widget() {
  const meditationData = response.data as MeditationData;
  const metaData = response.meta as MetaData;
  const { weeklyMinutes, currentStreak, totalSessions } = meditationData;
  const { primaryColor } = metaData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ color: primaryColor }}>
              Meditation Streak
            </Typography>
            <Typography variant="h3" fontWeight={700} sx={{ color: '#1F2937' }}>
              {currentStreak} Days
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Total Sessions: {totalSessions}
            </Typography>
          </Box>

          <BarChart
            height={140}
            series={[
              {
                data: weeklyMinutes.map((d) => d.minutes),
                color: primaryColor,
              },
            ]}
            xAxis={[
              {
                data: weeklyMinutes.map((d) => d.day),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#6B7280',
                },
              },
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
